#!/usr/bin/env node
// super-mem Context Loader - SessionStart hook
//
// Generated by super-mem setup for: __PROJECT_NAME__
// On every session start under __PROJECT_ROOT__:
// 1. Builds combined context from Brain + Memory + Daily logs
// 2. Writes to .claude/loaded-context.md (no size limit)
// 3. Appends session-start entry to today's daily file
// 4. Returns small additionalContext with stats + instruction

const fs = require('fs');
const path = require('path');

// --- Configuration (filled in by setup) ---
const PROJECT_ROOT = '__PROJECT_ROOT__';
const PROJECT_NAME = '__PROJECT_NAME__';
const BRAIN_DIR = path.join(PROJECT_ROOT, '__BRAIN_DIR__');
const DAILY_DIR = path.join(BRAIN_DIR, 'daily');
const MEMORY_DIR = '__MEMORY_DIR__';
const CONTEXT_FILE = path.join(PROJECT_ROOT, '.claude', 'loaded-context.md');
const DAILY_RETENTION_DAYS = 14;

function isUnderProject(cwd) {
  return cwd.toLowerCase().startsWith(PROJECT_ROOT.toLowerCase());
}

function walkDir(dir, excludeDirs = []) {
  const results = [];
  try {
    const entries = fs.readdirSync(dir, { withFileTypes: true });
    for (const entry of entries) {
      const fullPath = path.join(dir, entry.name);
      if (entry.isDirectory()) {
        if (!excludeDirs.includes(fullPath)) {
          results.push(...walkDir(fullPath, excludeDirs));
        }
      } else if (entry.isFile() && entry.name.endsWith('.md')) {
        results.push(fullPath);
      }
    }
  } catch (_) {}
  return results;
}

function loadBrain() {
  const files = walkDir(BRAIN_DIR, [DAILY_DIR]);
  if (files.length === 0) return { content: '', count: 0 };

  let out = `## ${PROJECT_NAME} Brain\n\n`;
  out += `_Source: \`${BRAIN_DIR}\` | ${files.length} files_\n\n`;

  for (const filePath of files) {
    const rel = path.relative(BRAIN_DIR, filePath).replace(/\\/g, '/');
    try {
      const content = fs.readFileSync(filePath, 'utf8').trim();
      if (content) {
        out += `### ${rel}\n\n${content}\n\n---\n\n`;
      }
    } catch (_) {}
  }

  return { content: out, count: files.length };
}

function loadMemory() {
  let files;
  try {
    files = fs.readdirSync(MEMORY_DIR, { withFileTypes: true })
      .filter(e => e.isFile() && e.name.endsWith('.md') && e.name !== 'MEMORY.md')
      .map(e => e.name)
      .sort();
  } catch (_) {
    return { content: '', count: 0 };
  }

  if (files.length === 0) return { content: '', count: 0 };

  let out = `## Auto-Memory (${files.length} files)\n\n`;

  for (const filename of files) {
    try {
      const content = fs.readFileSync(path.join(MEMORY_DIR, filename), 'utf8').trim();
      if (content) {
        out += `### ${filename.replace('.md', '')}\n\n${content}\n\n---\n\n`;
      }
    } catch (_) {}
  }

  return { content: out, count: files.length };
}

function getDateStr(date) {
  const y = date.getFullYear();
  const m = String(date.getMonth() + 1).padStart(2, '0');
  const d = String(date.getDate()).padStart(2, '0');
  return `${y}-${m}-${d}`;
}

function loadDailyLogs() {
  let files;
  try {
    files = fs.readdirSync(DAILY_DIR, { withFileTypes: true })
      .filter(e => e.isFile() && e.name.endsWith('.md'))
      .map(e => e.name)
      .sort()
      .reverse();
  } catch (_) {
    return { content: '', count: 0 };
  }

  if (files.length === 0) return { content: '', count: 0 };

  const cutoff = new Date();
  cutoff.setDate(cutoff.getDate() - DAILY_RETENTION_DAYS);
  const cutoffStr = getDateStr(cutoff);

  const recentFiles = files.filter(f => f.replace('.md', '') >= cutoffStr);
  if (recentFiles.length === 0) return { content: '', count: 0 };

  let out = `## Daily Log (last ${recentFiles.length} days)\n\n`;

  for (const filename of recentFiles) {
    try {
      const content = fs.readFileSync(path.join(DAILY_DIR, filename), 'utf8').trim();
      if (content) {
        out += `${content}\n\n---\n\n`;
      }
    } catch (_) {}
  }

  return { content: out, count: recentFiles.length };
}

function appendSessionStart() {
  const now = new Date();
  const dateStr = getDateStr(now);
  const timeStr = `${String(now.getHours()).padStart(2, '0')}:${String(now.getMinutes()).padStart(2, '0')}`;
  const dailyFile = path.join(DAILY_DIR, `${dateStr}.md`);

  try {
    fs.mkdirSync(DAILY_DIR, { recursive: true });
  } catch (_) {}

  let existing = '';
  try {
    existing = fs.readFileSync(dailyFile, 'utf8');
  } catch (_) {}

  const sessionCount = (existing.match(/#### Session \d+/g) || []).length + 1;

  let entry = '';
  if (!existing) {
    entry = `# Daily Log ${dateStr}\n\n`;
  }
  entry += `\n#### Session ${sessionCount} | ${timeStr}\n`;

  fs.appendFileSync(dailyFile, entry, 'utf8');

  return { sessionNumber: sessionCount, time: timeStr, date: dateStr };
}

function main() {
  const cwd = process.cwd();

  if (!isUnderProject(cwd)) {
    process.stdout.write(JSON.stringify({}));
    return;
  }

  const session = appendSessionStart();

  const brain = loadBrain();
  const memory = loadMemory();
  const daily = loadDailyLogs();
  const fullContent = brain.content + memory.content + daily.content;

  try {
    fs.mkdirSync(path.dirname(CONTEXT_FILE), { recursive: true });
    fs.writeFileSync(CONTEXT_FILE, fullContent, 'utf8');
  } catch (_) {}

  const sizeKB = Math.round(fullContent.length / 1024);
  const tokens = Math.round(fullContent.length / 4);

  const summary = [
    `${PROJECT_NAME} context ready: ${CONTEXT_FILE}`,
    `Brain: ${brain.count} files | Memory: ${memory.count} files | Daily: ${daily.count} days | ${sizeKB}KB (~${tokens} tokens)`,
    `Session: ${session.sessionNumber} | ${session.date} ${session.time}`,
    `Say "session start" to load full context.`,
  ].join('\n');

  process.stdout.write(
    JSON.stringify({
      hookSpecificOutput: {
        hookEventName: 'SessionStart',
        additionalContext: summary,
      },
    }),
  );
}

main();
